#!/usr/bin/env bash
set -euo pipefail

TMPDIR_SECURE="$(mktemp -d)"
chmod 700 "$TMPDIR_SECURE"
trap 'rm -rf "$TMPDIR_SECURE"' EXIT

CREDS_FILE="$TMPDIR_SECURE/gcp-oauth.keys.json"
security find-generic-password -a "$USER" -s "google-drive-mcp-oauth" -w > "$CREDS_FILE"
chmod 600 "$CREDS_FILE"

export GOOGLE_DRIVE_OAUTH_CREDENTIALS="$CREDS_FILE"
export GOOGLE_DRIVE_MCP_USE_KEYCHAIN=1

exec node node_modules/@piotr-agier/google-drive-mcp/dist/index.js "$@"

/**
 * AWS SSO Auto-Refresh Extension
 *
 * - On session start: checks if the AWS SSO session is valid and refreshes if not.
 * - Background polling (every 5 min): detects mid-session expiry and auto-refreshes.
 * - /aws-refresh command: manual trigger.
 * - Status bar: shows current SSO state (checking / valid / refreshing / error).
 *
 * Profile selection:
 *   IS_SANDBOX=1  → scw-agentic-bedrock-sso  (device-code, no-browser)
 *   otherwise     → scw-agentic-bedrock
 */

import { readFile as fsReadFile } from "node:fs/promises";
import type { ExtensionAPI, ExtensionContext } from "@earendil-works/pi-coding-agent";

// ---------------------------------------------------------------------------
// Public types (exported for testing)
// ---------------------------------------------------------------------------

export type ExecFn = (
  command: string,
  args: string[],
  options?: { timeout?: number },
) => Promise<{ code: number; stdout: string; stderr: string; killed: boolean }>;

export type ReadFileFn = (path: string) => Promise<string>;

export interface UICallbacks {
  setStatus(text: string): void;
  notify(msg: string, type: "info" | "warning" | "error"): void;
}

export interface RefreshState {
  refreshing: boolean;
}

export interface ValidityResult {
  valid: boolean;
  /** Human-readable detail for diagnostics (exit code, trimmed stderr). */
  detail: string;
}

// ---------------------------------------------------------------------------
// Constants (exported so tests can reference POLL_INTERVAL_MS)
// ---------------------------------------------------------------------------

export const POLL_INTERVAL_MS = 30 * 60 * 1000; // 30 minutes
export const AUTH_ERROR_DEBOUNCE_MS = 30_000; // 30 seconds
const SCRIPT_PATH = "scripts/aws-auth-refresh.sh";
const LOG_PATH = "/tmp/aws-sso-refresh.log";
const VALIDITY_TIMEOUT_MS = 15_000;
const REFRESH_TIMEOUT_MS = 120_000;
const LOG_POLL_INTERVAL_MS = 1_000;

// ---------------------------------------------------------------------------
// Auth error detection
// ---------------------------------------------------------------------------

/**
 * Returns true when an HTTP response from a provider (e.g. AWS Bedrock) indicates
 * an authentication or token-expiry failure that a fresh SSO login can fix.
 *
 * Handles:
 *   - 401 Unauthorized (generic auth failure)
 *   - 403 Forbidden    (AWS token expired / insufficient sig)
 *   - 400 Bad Request  only when x-amzn-errortype is ExpiredToken or InvalidSignature
 *                      (the latter covers clock-skew after laptop sleep)
 */
export function isAuthError(status: number, headers: Record<string, string>): boolean {
  if (status === 401 || status === 403) return true;
  if (status === 400) {
    const errorType = headers["x-amzn-errortype"] ?? headers["X-Amzn-Errortype"] ?? "";
    return errorType.includes("ExpiredToken") || errorType.includes("InvalidSignature");
  }
  return false;
}

export function isTokenMissingError(detail: string): boolean {
  return detail.includes("does not exist");
}

// ---------------------------------------------------------------------------
// Pure helpers
// ---------------------------------------------------------------------------

export function getAwsProfile(): string {
  return process.env.IS_SANDBOX === "1" ? "scw-agentic-bedrock-sso" : "scw-agentic-bedrock";
}

export async function checkSessionValid(exec: ExecFn, profile: string): Promise<ValidityResult> {
  try {
    const result = await exec("aws", ["sts", "get-caller-identity", "--profile", profile], {
      timeout: VALIDITY_TIMEOUT_MS,
    });
    if (result.code === 0) {
      return { valid: true, detail: "exit 0" };
    }
    const stderr = result.stderr.trim().split("\n")[0] ?? "(no stderr)";
    return { valid: false, detail: `exit ${result.code}: ${stderr}` };
  } catch (err: unknown) {
    const msg = err instanceof Error ? err.message : String(err);
    return { valid: false, detail: `threw: ${msg}` };
  }
}

export async function runDeviceCodeLogin(
  exec: ExecFn,
  profile: string,
  readFile: ReadFileFn,
  ui: UICallbacks,
): Promise<boolean> {
  let done = false;
  let resolveCancel!: () => void;
  const cancelSignal = new Promise<void>((r) => { resolveCancel = r; });
  let lastSeenContent = "";

  async function pollLog() {
    while (!done) {
      await Promise.race([
        new Promise<void>((r) => setTimeout(r, LOG_POLL_INTERVAL_MS)),
        cancelSignal,
      ]);
      if (done) break;
      try {
        const content = await readFile(LOG_PATH);
        if (content && content !== lastSeenContent) {
          const newPart = content.slice(lastSeenContent.length);
          lastSeenContent = content;
          const lines = newPart.split("\n").map((l) => l.trim()).filter(Boolean);
          for (const line of lines) {
            ui.notify(line, "info");
          }
        }
      } catch {
        // log file may not exist yet
      }
    }
  }

  const pollPromise = pollLog();

  try {
    const result = await exec(
      "bash",
      ["-c", `aws sso login --profile ${profile} --no-browser --use-device-code 2>&1 | tee ${LOG_PATH}`],
      { timeout: REFRESH_TIMEOUT_MS },
    );
    return result.code === 0;
  } catch {
    return false;
  } finally {
    done = true;
    resolveCancel();
    await pollPromise;
  }
}

export async function runRefreshScript(
  exec: ExecFn,
  scriptPath: string,
  readFile: ReadFileFn,
  ui: UICallbacks,
): Promise<boolean> {
  let done = false;
  let resolveCancel!: () => void;
  const cancelSignal = new Promise<void>((r) => { resolveCancel = r; });
  let lastSeenContent = "";

  async function pollLog() {
    while (!done) {
      await Promise.race([
        new Promise<void>((r) => setTimeout(r, LOG_POLL_INTERVAL_MS)),
        cancelSignal,
      ]);
      if (done) break;
      try {
        const content = await readFile(LOG_PATH);
        if (content && content !== lastSeenContent) {
          const newPart = content.slice(lastSeenContent.length);
          lastSeenContent = content;
          const lines = newPart.split("\n").map((l) => l.trim()).filter(Boolean);
          for (const line of lines) {
            ui.notify(line, "info");
          }
        }
      } catch {
        // log file may not exist yet
      }
    }
  }

  const pollPromise = pollLog();

  try {
    const result = await exec("bash", [scriptPath], { timeout: REFRESH_TIMEOUT_MS });
    return result.code === 0;
  } catch {
    return false;
  } finally {
    done = true;
    resolveCancel();
    await pollPromise;
  }
}

// ---------------------------------------------------------------------------
// Orchestration
// ---------------------------------------------------------------------------

export async function checkAndRefreshIfNeeded(
  exec: ExecFn,
  scriptPath: string,
  profile: string,
  readFile: ReadFileFn,
  ui: UICallbacks,
  state: RefreshState,
  trigger: string,
): Promise<"valid" | "refreshed" | "error" | "skipped"> {
  if (state.refreshing) return "skipped";

  const { valid, detail } = await checkSessionValid(exec, profile);

  if (valid) {
    ui.setStatus("✅ AWS SSO valid");
    return "valid";
  }

  state.refreshing = true;
  ui.setStatus("🔄 AWS SSO refreshing...");

  let ok = false;
  try {
    if (isTokenMissingError(detail)) {
      ui.notify(`AWS SSO has no token — starting device-code login... [trigger: ${trigger}]`, "warning");
      ok = await runDeviceCodeLogin(exec, profile, readFile, ui);
    } else {
      ui.notify(`AWS SSO session invalid — refreshing... [trigger: ${trigger}] [sts: ${detail}]`, "warning");
      ok = await runRefreshScript(exec, scriptPath, readFile, ui);
    }
  } finally {
    state.refreshing = false;
  }

  if (ok) {
    ui.setStatus("✅ AWS SSO valid");
    ui.notify("AWS SSO session refreshed", "info");
    return "refreshed";
  } else {
    ui.setStatus("❌ AWS SSO refresh failed");
    ui.notify("AWS SSO refresh failed — run /aws-refresh to retry", "error");
    return "error";
  }
}

// ---------------------------------------------------------------------------
// Extension factory
// ---------------------------------------------------------------------------

export default function (pi: ExtensionAPI) {
  let pollTimer: ReturnType<typeof setInterval> | undefined;
  const state: RefreshState = { refreshing: false };
  let lastAuthErrorMs = 0;

  const exec: ExecFn = (cmd, args, opts) => pi.exec(cmd, args, opts);
  const readFile: ReadFileFn = (path) => fsReadFile(path, "utf8");

  function makeUI(ctx: ExtensionContext): UICallbacks {
    return {
      setStatus: (text) => ctx.ui.setStatus("aws-sso", text),
      notify: (msg, type) => ctx.ui.notify(msg, type),
    };
  }

  // Stored so the polling callback can reach the UI without a live ctx.
  // Updated on each session_start and on manual /aws-refresh invocations.
  let currentUI: UICallbacks | undefined;

  function stopPolling() {
    if (pollTimer !== undefined) {
      clearInterval(pollTimer);
      pollTimer = undefined;
    }
  }

  function startPolling() {
    stopPolling();
    pollTimer = setInterval(() => {
      if (!currentUI) return;
      const ui = currentUI;
      checkAndRefreshIfNeeded(exec, SCRIPT_PATH, getAwsProfile(), readFile, ui, state, "poll").catch((err: unknown) => {
      });
    }, POLL_INTERVAL_MS);
  }

  pi.on("after_provider_response", (event) => {
    if (!currentUI) return;
    if (!isAuthError(event.status, event.headers)) return;

    const now = Date.now();
    if (now - lastAuthErrorMs < AUTH_ERROR_DEBOUNCE_MS) return;
    lastAuthErrorMs = now;

    const ui = currentUI;
    checkAndRefreshIfNeeded(exec, SCRIPT_PATH, getAwsProfile(), readFile, ui, state, `after_provider_response(${event.status})`).catch((err: unknown) => {
    });
  });

  pi.on("session_start", async (_event, ctx) => {
    currentUI = makeUI(ctx);
    ctx.ui.setStatus("aws-sso", "🔍 AWS SSO checking...");
    await checkAndRefreshIfNeeded(exec, SCRIPT_PATH, getAwsProfile(), readFile, currentUI, state, "session_start");
    startPolling();
  });

  pi.on("session_shutdown", async () => {
    stopPolling();
  });

  pi.registerCommand("aws-refresh", {
    description: "Manually refresh the AWS SSO session",
    handler: async (_args, ctx) => {
      currentUI = makeUI(ctx);
      ctx.ui.setStatus("aws-sso", "🔍 AWS SSO checking...");
      await checkAndRefreshIfNeeded(exec, SCRIPT_PATH, getAwsProfile(), readFile, currentUI, state, "manual(/aws-refresh)");
    },
  });
}

