import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
import {
  getAwsProfile,
  checkSessionValid,
  runRefreshScript,
  runDeviceCodeLogin,
  checkAndRefreshIfNeeded,
  isAuthError,
  isTokenMissingError,
  POLL_INTERVAL_MS,
  AUTH_ERROR_DEBOUNCE_MS,
  type ExecFn,
  type ReadFileFn,
  type UICallbacks,
  type RefreshState,
} from "../aws-sso-refresh.ts";
import extensionFactory from "../aws-sso-refresh.ts";

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeExec(code: number, stdout = "", stderr = ""): ExecFn {
  return vi.fn().mockResolvedValue({ code, stdout, stderr, killed: false });
}

function makeUI(): { ui: UICallbacks; setStatusCalls: string[]; notifyCalls: Array<{ msg: string; type: string }> } {
  const setStatusCalls: string[] = [];
  const notifyCalls: Array<{ msg: string; type: string }> = [];
  const ui: UICallbacks = {
    setStatus: (text) => setStatusCalls.push(text),
    notify: (msg, type) => notifyCalls.push({ msg, type }),
  };
  return { ui, setStatusCalls, notifyCalls };
}

function makeRefreshState(): RefreshState {
  return { refreshing: false };
}

function makeReadFile(sequence: string[]): ReadFileFn {
  let call = 0;
  return vi.fn().mockImplementation(async (_path: string) => {
    const val = sequence[Math.min(call, sequence.length - 1)] ?? "";
    call++;
    return val;
  });
}

// ---------------------------------------------------------------------------
// getAwsProfile
// ---------------------------------------------------------------------------

describe("getAwsProfile", () => {
  afterEach(() => {
    delete process.env.IS_SANDBOX;
  });

  it("returns sandbox profile when IS_SANDBOX=1", () => {
    process.env.IS_SANDBOX = "1";
    expect(getAwsProfile()).toBe("scw-agentic-bedrock-sso");
  });

  it("returns non-sandbox profile when IS_SANDBOX is unset", () => {
    delete process.env.IS_SANDBOX;
    expect(getAwsProfile()).toBe("scw-agentic-bedrock");
  });

  it("returns non-sandbox profile when IS_SANDBOX=0", () => {
    process.env.IS_SANDBOX = "0";
    expect(getAwsProfile()).toBe("scw-agentic-bedrock");
  });
});

// ---------------------------------------------------------------------------
// checkSessionValid
// ---------------------------------------------------------------------------

describe("checkSessionValid", () => {
  it("returns valid:true when exec exits with code 0", async () => {
    const exec = makeExec(0, '{"UserId":"AROA...","Account":"123"}');
    const result = await checkSessionValid(exec, "scw-agentic-bedrock-sso");
    expect(result.valid).toBe(true);
    expect(result.detail).toBe("exit 0");
  });

  it("passes the correct aws command and profile arg", async () => {
    const exec = makeExec(0);
    await checkSessionValid(exec, "my-profile");
    expect(exec).toHaveBeenCalledWith(
      "aws",
      ["sts", "get-caller-identity", "--profile", "my-profile"],
      expect.objectContaining({ timeout: expect.any(Number) }),
    );
  });

  it("returns valid:false with exit code detail when exec exits with non-zero code", async () => {
    const exec = makeExec(1, "", "Error loading SSO Token");
    const result = await checkSessionValid(exec, "scw-agentic-bedrock-sso");
    expect(result.valid).toBe(false);
    expect(result.detail).toMatch(/exit 1/);
    expect(result.detail).toMatch(/Error loading SSO Token/);
  });

  it("returns valid:false with threw detail when exec throws", async () => {
    const exec = vi.fn().mockRejectedValue(new Error("network error")) as ExecFn;
    const result = await checkSessionValid(exec, "scw-agentic-bedrock-sso");
    expect(result.valid).toBe(false);
    expect(result.detail).toMatch(/threw: network error/);
  });
});

// ---------------------------------------------------------------------------
// runRefreshScript
// ---------------------------------------------------------------------------

describe("runRefreshScript", () => {
  it("returns true when exec exits with code 0", async () => {
    const exec = makeExec(0);
    const readFile = makeReadFile([]);
    const { ui } = makeUI();
    const result = await runRefreshScript(exec, "scripts/aws-auth-refresh.sh", readFile, ui);
    expect(result).toBe(true);
  });

  it("passes the correct bash command and script path", async () => {
    const exec = makeExec(0);
    const readFile = makeReadFile([]);
    const { ui } = makeUI();
    await runRefreshScript(exec, "scripts/aws-auth-refresh.sh", readFile, ui);
    expect(exec).toHaveBeenCalledWith(
      "bash",
      ["scripts/aws-auth-refresh.sh"],
      expect.objectContaining({ timeout: expect.any(Number) }),
    );
  });

  it("returns false when exec exits with non-zero code", async () => {
    const exec = makeExec(2, "", "Login failed");
    const readFile = makeReadFile([]);
    const { ui } = makeUI();
    const result = await runRefreshScript(exec, "scripts/aws-auth-refresh.sh", readFile, ui);
    expect(result).toBe(false);
  });

  it("returns false when exec throws", async () => {
    const exec = vi.fn().mockRejectedValue(new Error("aborted")) as ExecFn;
    const readFile = makeReadFile([]);
    const { ui } = makeUI();
    const result = await runRefreshScript(exec, "scripts/aws-auth-refresh.sh", readFile, ui);
    expect(result).toBe(false);
  });

  it("surfaces new log lines as notifications while the script runs", async () => {
    vi.useFakeTimers();
    // exec takes a while to resolve — we'll advance timers to trigger polling
    let resolveExec!: () => void;
    const execPromise = new Promise<{ code: number; stdout: string; stderr: string; killed: boolean }>((resolve) => {
      resolveExec = () => resolve({ code: 0, stdout: "", stderr: "", killed: false });
    });
    const exec = vi.fn().mockReturnValue(execPromise) as ExecFn;

    // First poll returns the URL immediately; second poll returns same content (no repeat notify)
    const readFile = makeReadFile(["https://device.sso.eu-central-1.amazonaws.com/\nEnter code: ABCD-1234"]);
    const { ui, notifyCalls } = makeUI();

    const refreshPromise = runRefreshScript(exec, "scripts/aws-auth-refresh.sh", readFile, ui);

    // Advance past the first poll tick
    await vi.advanceTimersByTimeAsync(1100);

    // URL should have been notified
    expect(notifyCalls.some((n) => n.msg.includes("device.sso"))).toBe(true);

    resolveExec();
    await refreshPromise;

    vi.useRealTimers();
  });

  it("does not repeat the same log line in multiple notifications", async () => {
    vi.useFakeTimers();
    let resolveExec!: () => void;
    const execPromise = new Promise<{ code: number; stdout: string; stderr: string; killed: boolean }>((resolve) => {
      resolveExec = () => resolve({ code: 0, stdout: "", stderr: "", killed: false });
    });
    const exec = vi.fn().mockReturnValue(execPromise) as ExecFn;

    // Both polls return the same content
    const readFile = makeReadFile(["same line", "same line"]);
    const { ui, notifyCalls } = makeUI();

    const refreshPromise = runRefreshScript(exec, "scripts/aws-auth-refresh.sh", readFile, ui);

    await vi.advanceTimersByTimeAsync(1100);
    await vi.advanceTimersByTimeAsync(1100);

    const sameLineNotifs = notifyCalls.filter((n) => n.msg.includes("same line"));
    expect(sameLineNotifs.length).toBe(1);

    resolveExec();
    await refreshPromise;

    vi.useRealTimers();
  });
});

// ---------------------------------------------------------------------------
// runDeviceCodeLogin
// ---------------------------------------------------------------------------

describe("runDeviceCodeLogin", () => {
  it("returns true when exec exits with code 0", async () => {
    const exec = makeExec(0);
    const readFile = makeReadFile([]);
    const { ui } = makeUI();
    const result = await runDeviceCodeLogin(exec, "my-profile", readFile, ui);
    expect(result).toBe(true);
  });

  it("returns false when exec exits with non-zero code", async () => {
    const exec = makeExec(2, "", "Login failed");
    const readFile = makeReadFile([]);
    const { ui } = makeUI();
    const result = await runDeviceCodeLogin(exec, "my-profile", readFile, ui);
    expect(result).toBe(false);
  });

  it("returns false when exec throws", async () => {
    const exec = vi.fn().mockRejectedValue(new Error("aborted")) as ExecFn;
    const readFile = makeReadFile([]);
    const { ui } = makeUI();
    const result = await runDeviceCodeLogin(exec, "my-profile", readFile, ui);
    expect(result).toBe(false);
  });

  it("passes the profile to the aws sso login command", async () => {
    const exec = makeExec(0);
    const readFile = makeReadFile([]);
    const { ui } = makeUI();
    await runDeviceCodeLogin(exec, "my-profile", readFile, ui);
    // command string passed to bash -c must include profile and --use-device-code
    const call = (exec as ReturnType<typeof vi.fn>).mock.calls[0];
    expect(call[0]).toBe("bash");
    const script = call[1].join(" ");
    expect(script).toContain("my-profile");
    expect(script).toContain("--use-device-code");
  });

  it("surfaces log lines as notifications while the command runs", async () => {
    vi.useFakeTimers();
    let resolveExec!: () => void;
    const execPromise = new Promise<{ code: number; stdout: string; stderr: string; killed: boolean }>((resolve) => {
      resolveExec = () => resolve({ code: 0, stdout: "", stderr: "", killed: false });
    });
    const exec = vi.fn().mockReturnValue(execPromise) as ExecFn;
    const readFile = makeReadFile(["https://device.sso.eu-central-1.amazonaws.com/\nEnter code: ABCD-1234"]);
    const { ui, notifyCalls } = makeUI();

    const loginPromise = runDeviceCodeLogin(exec, "my-profile", readFile, ui);
    await vi.advanceTimersByTimeAsync(1100);
