describe("extension factory", () => {
  type Handler = (event: Record<string, unknown>, ctx: MockCtx) => Promise<void>;
  type CommandDef = { description: string; handler: (args: string, ctx: MockCtx) => Promise<void> };

  interface MockCtx {
    ui: {
      // Matches pi's ctx.ui.setStatus(id, text) signature
      setStatus(id: string, text: string): void;
      notify(msg: string, type: string): void;
      setStatusCalls: string[];
      notifyCalls: Array<{ msg: string; type: string }>;
    };
  }

  function makeMockPi(execImpl: ExecFn) {
    const handlers: Record<string, Handler[]> = {};
    const commands: Record<string, CommandDef> = {};

    const mockPi = {
      exec: execImpl,
      on: vi.fn((event: string, handler: Handler) => {
        if (!handlers[event]) handlers[event] = [];
        handlers[event].push(handler);
      }),
      registerCommand: vi.fn((name: string, def: CommandDef) => {
        commands[name] = def;
      }),
      async fire(event: string, eventObj: Record<string, unknown>, ctx: MockCtx) {
        for (const h of handlers[event] ?? []) {
          await h(eventObj, ctx);
        }
      },
      commands,
      handlers,
    };
    return mockPi;
  }

  function makeMockCtx(): MockCtx {
    const setStatusCalls: string[] = [];
    const notifyCalls: Array<{ msg: string; type: string }> = [];
    return {
      ui: {
        // pi's setStatus signature is (id: string, text: string) — capture the text (second arg)
        setStatus: (_id: string, text: string) => setStatusCalls.push(text),
        notify: (msg, type) => notifyCalls.push({ msg, type }),
        setStatusCalls,
        notifyCalls,
      },
    };
  }

  beforeEach(() => {
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  it("registers session_start, session_shutdown, and aws-refresh command", () => {
    const exec = makeExec(0);
    const pi = makeMockPi(exec);
    extensionFactory(pi as never);

    expect(pi.on).toHaveBeenCalledWith("session_start", expect.any(Function));
    expect(pi.on).toHaveBeenCalledWith("session_shutdown", expect.any(Function));
    expect(pi.registerCommand).toHaveBeenCalledWith("aws-refresh", expect.any(Object));
  });

  it("checks validity on session_start and sets status to valid when session is good", async () => {
    const exec = makeExec(0);
    const pi = makeMockPi(exec);
    extensionFactory(pi as never);

    const ctx = makeMockCtx();
    await pi.fire("session_start", { type: "session_start", reason: "startup" }, ctx);

    expect(ctx.ui.setStatusCalls.some((s) => s.includes("✅"))).toBe(true);
  });

  it("runs the refresh script on session_start when session is expired", async () => {
    const exec = vi
      .fn()
      .mockResolvedValueOnce({ code: 1, stdout: "", stderr: "expired", killed: false })
      .mockResolvedValueOnce({ code: 0, stdout: "", stderr: "", killed: false }) as ExecFn;
    const pi = makeMockPi(exec);
    extensionFactory(pi as never);

    const ctx = makeMockCtx();
    await pi.fire("session_start", { type: "session_start", reason: "startup" }, ctx);

    // exec called twice: once for check, once for refresh
    expect(exec).toHaveBeenCalledTimes(2);
    expect(exec).toHaveBeenNthCalledWith(1, "aws", expect.arrayContaining(["sts", "get-caller-identity"]), expect.anything());
    expect(exec).toHaveBeenNthCalledWith(2, "bash", ["scripts/aws-auth-refresh.sh"], expect.anything());
    expect(ctx.ui.notifyCalls.some((n) => n.type === "info")).toBe(true);
  });

  it("starts polling interval after session_start", async () => {
    const exec = makeExec(0);
    const pi = makeMockPi(exec);
    extensionFactory(pi as never);

    const ctx = makeMockCtx();
    await pi.fire("session_start", { type: "session_start", reason: "startup" }, ctx);

    const callsAfterStart = (exec as ReturnType<typeof vi.fn>).mock.calls.length;

    // Advance time by one poll interval
    await vi.advanceTimersByTimeAsync(POLL_INTERVAL_MS);

    expect((exec as ReturnType<typeof vi.fn>).mock.calls.length).toBeGreaterThan(callsAfterStart);
  });

  it("clears the polling interval on session_shutdown", async () => {
    const exec = makeExec(0);
    const pi = makeMockPi(exec);
    extensionFactory(pi as never);

    const ctx = makeMockCtx();
    await pi.fire("session_start", { type: "session_start", reason: "startup" }, ctx);
    await pi.fire("session_shutdown", { type: "session_shutdown", reason: "quit" }, ctx);

    const callsAfterShutdown = (exec as ReturnType<typeof vi.fn>).mock.calls.length;

    // Advance time — no more calls should happen
    await vi.advanceTimersByTimeAsync(POLL_INTERVAL_MS * 3);

    expect((exec as ReturnType<typeof vi.fn>).mock.calls.length).toBe(callsAfterShutdown);
  });

  it("/aws-refresh command triggers a check", async () => {
    const exec = makeExec(0);
    const pi = makeMockPi(exec);
    extensionFactory(pi as never);

    const ctx = makeMockCtx();
    await pi.commands["aws-refresh"].handler("", ctx);

    expect(exec).toHaveBeenCalledWith("aws", expect.arrayContaining(["sts", "get-caller-identity"]), expect.anything());
    expect(ctx.ui.setStatusCalls.some((s) => s.includes("✅"))).toBe(true);
  });

  it("registers after_provider_response handler", () => {
    const exec = makeExec(0);
    const pi = makeMockPi(exec);
    extensionFactory(pi as never);

    expect(pi.on).toHaveBeenCalledWith("after_provider_response", expect.any(Function));
  });

  it("triggers refresh when after_provider_response fires with 401", async () => {
    // session invalid so refresh will run
    const exec = vi
      .fn()
      .mockResolvedValue({ code: 1, stdout: "", stderr: "expired", killed: false }) as ExecFn;
    const pi = makeMockPi(exec);
    extensionFactory(pi as never);

    const ctx = makeMockCtx();
    // Start session first so currentUI is set
    await pi.fire("session_start", { type: "session_start", reason: "startup" }, ctx);

    const callsAfterStart = (exec as ReturnType<typeof vi.fn>).mock.calls.length;

    await pi.fire("after_provider_response", { type: "after_provider_response", status: 401, headers: {} }, ctx);

    expect((exec as ReturnType<typeof vi.fn>).mock.calls.length).toBeGreaterThan(callsAfterStart);
  });

  it("triggers refresh when after_provider_response fires with 403", async () => {
    const exec = vi
      .fn()
      .mockResolvedValue({ code: 1, stdout: "", stderr: "expired", killed: false }) as ExecFn;
    const pi = makeMockPi(exec);
    extensionFactory(pi as never);

    const ctx = makeMockCtx();
    await pi.fire("session_start", { type: "session_start", reason: "startup" }, ctx);

    const callsAfterStart = (exec as ReturnType<typeof vi.fn>).mock.calls.length;

    await pi.fire("after_provider_response", { type: "after_provider_response", status: 403, headers: {} }, ctx);

    expect((exec as ReturnType<typeof vi.fn>).mock.calls.length).toBeGreaterThan(callsAfterStart);
  });

  it("does not trigger refresh for non-auth provider responses", async () => {
    const exec = makeExec(0);
    const pi = makeMockPi(exec);
    extensionFactory(pi as never);

    const ctx = makeMockCtx();
    await pi.fire("session_start", { type: "session_start", reason: "startup" }, ctx);

    const callsAfterStart = (exec as ReturnType<typeof vi.fn>).mock.calls.length;

    await pi.fire("after_provider_response", { type: "after_provider_response", status: 200, headers: {} }, ctx);
    await pi.fire("after_provider_response", { type: "after_provider_response", status: 500, headers: {} }, ctx);
    await pi.fire("after_provider_response", { type: "after_provider_response", status: 429, headers: {} }, ctx);

    expect((exec as ReturnType<typeof vi.fn>).mock.calls.length).toBe(callsAfterStart);
  });

  it("debounces repeated auth errors within AUTH_ERROR_DEBOUNCE_MS", async () => {
    const exec = vi
      .fn()
      .mockResolvedValue({ code: 1, stdout: "", stderr: "expired", killed: false }) as ExecFn;
    const pi = makeMockPi(exec);
    extensionFactory(pi as never);

    const ctx = makeMockCtx();
    await pi.fire("session_start", { type: "session_start", reason: "startup" }, ctx);

    // Count sts calls after startup
    const stsAfterStart = (exec as ReturnType<typeof vi.fn>).mock.calls.filter(
      (c) => c[0] === "aws" && c[1]?.includes("sts"),
    ).length;

    // Fire three 401s in quick succession — only the first should trigger a new sts check
    await pi.fire("after_provider_response", { type: "after_provider_response", status: 401, headers: {} }, ctx);
    await pi.fire("after_provider_response", { type: "after_provider_response", status: 401, headers: {} }, ctx);
    await pi.fire("after_provider_response", { type: "after_provider_response", status: 401, headers: {} }, ctx);

    // Advance time but not past debounce window
    await vi.advanceTimersByTimeAsync(AUTH_ERROR_DEBOUNCE_MS - 1000);

    const stsAfterThree = (exec as ReturnType<typeof vi.fn>).mock.calls.filter(
      (c) => c[0] === "aws" && c[1]?.includes("sts"),
    ).length;

    // Only one extra sts check should have run (from the first 401 only)
    expect(stsAfterThree - stsAfterStart).toBe(1);
  });

  it("fires a new refresh after debounce window expires", async () => {
    const exec = vi
      .fn()
      .mockResolvedValue({ code: 1, stdout: "", stderr: "expired", killed: false }) as ExecFn;
    const pi = makeMockPi(exec);
    extensionFactory(pi as never);

    const ctx = makeMockCtx();
    await pi.fire("session_start", { type: "session_start", reason: "startup" }, ctx);

    // First 401: triggers a check
    await pi.fire("after_provider_response", { type: "after_provider_response", status: 401, headers: {} }, ctx);

    const stsAfterFirst = (exec as ReturnType<typeof vi.fn>).mock.calls.filter(
      (c) => c[0] === "aws" && c[1]?.includes("sts"),
    ).length;

    // Advance past the debounce window
    await vi.advanceTimersByTimeAsync(AUTH_ERROR_DEBOUNCE_MS + 100);

    // Second 401: should trigger another check now that debounce has cleared
    await pi.fire("after_provider_response", { type: "after_provider_response", status: 401, headers: {} }, ctx);

    const stsAfterSecond = (exec as ReturnType<typeof vi.fn>).mock.calls.filter(
      (c) => c[0] === "aws" && c[1]?.includes("sts"),
    ).length;

    expect(stsAfterSecond).toBeGreaterThan(stsAfterFirst);
  });
});

